// Extract Excel attachment from the email
// The IMAP node puts attachments in binary data
const items = $input.all();
const results = [];

for (const item of items) {
  // Check for binary attachments
  const binaryKeys = Object.keys(item.binary || {});

  for (const key of binaryKeys) {
    const binary = item.binary[key];
    const fileName = binary.fileName || '';

    // Only process Excel files
    if (fileName.endsWith('.xlsx') || fileName.endsWith('.xls') || 
        binary.mimeType === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' ||
        binary.mimeType === 'application/vnd.ms-excel') {
      results.push({
        json: {
          fileName: fileName,
          subject: item.json.subject || '',
          from: item.json.from || '',
          date: item.json.date || '',
          binaryKey: key
        },
        binary: {
          data: binary
        }
      });
    }
  }
}

if (results.length === 0) {
  throw new Error('No Excel attachment found in email');
}

return results;

// Parse the password-protected Excel file
// Uses SheetJS (xlsx) which is available in n8n
const xlsx = require('xlsx');

const items = $input.all();
const allRows = [];

// SFF Excel password - store in n8n credentials/env var in production
const SFF_PASSWORD = $env.SFF_EXCEL_PASSWORD || 'REPLACE_WITH_PASSWORD';

for (const item of items) {
  const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');

  let workbook;
  try {
    workbook = xlsx.read(binaryData, {
      type: 'buffer',
      password: SFF_PASSWORD
    });
  } catch (err) {
    // Try without password in case it's not protected
    try {
      workbook = xlsx.read(binaryData, { type: 'buffer' });
    } catch (err2) {
      throw new Error(`Failed to read Excel file: ${err.message}`);
    }
  }

  const sheetName = workbook.SheetNames[0];
  const sheet = workbook.Sheets[sheetName];
  const jsonData = xlsx.utils.sheet_to_json(sheet, { defval: '' });

  for (const row of jsonData) {
    // Map SFF column names to our fields
    // SFF columns: Event Name, Location, FirstName, LastName, Email, No.Tickets, Booking ID, Event Date, Event Time
    const eventName = (row['Event Name'] || row['event_name'] || '').toString().trim();
    const firstName = (row['FirstName'] || row['First Name'] || row['first_name'] || '').toString().trim();
    const lastName = (row['LastName'] || row['Last Name'] || row['last_name'] || '').toString().trim();
    const email = (row['Email'] || row['email'] || '').toString().trim().toLowerCase();
    const ticketCount = parseInt(row['No.Tickets'] || row['No. Tickets'] || row['Tickets'] || row['ticket_count'] || '1', 10);
    const bookingId = (row['Booking ID'] || row['BookingID'] || row['booking_id'] || '').toString().trim();
    const eventDate = (row['Event Date'] || row['event_date'] || '').toString().trim();
    const eventTime = (row['Event Time'] || row['event_time'] || '').toString().trim();
    const location = (row['Location'] || row['location'] || '').toString().trim();

    // Skip rows without essential data
    if (!email || !eventName) continue;

    // Parse date from DD/MM/YYYY to YYYY-MM-DD
    let parsedDate = eventDate;
    if (eventDate.includes('/')) {
      const parts = eventDate.split('/');
      if (parts.length === 3) {
        parsedDate = `${parts[2]}-${parts[1].padStart(2, '0')}-${parts[0].padStart(2, '0')}`;
      }
    }

    allRows.push({
      json: {
        event_name: eventName,
        location: location,
        first_name: firstName,
        last_name: lastName,
        email: email,
        ticket_count: isNaN(ticketCount) ? 1 : ticketCount,
        booking_reference: bookingId,
        event_date: parsedDate,
        event_time: eventTime,
        source_email_subject: item.json.subject || '',
        source_email_date: item.json.date || ''
      }
    });
  }
}

if (allRows.length === 0) {
  throw new Error('No valid attendee rows found in Excel file');
}

return allRows;

// Merge the parsed attendee data with the matched event/session
const attendee = $('Parse SFF Excel').item.json;
const matchResult = $input.item.json;

// The RPC returns an array - take the first match
const match = Array.isArray(matchResult) ? matchResult[0] : matchResult;

if (!match || !match.event_id) {
  // Log warning but don't fail - store with null event_id for manual review
  return {
    json: {
      ...attendee,
      event_id: null,
      session_id: null,
      match_status: 'no_match',
      match_message: `No event found matching: ${attendee.event_name} on ${attendee.event_date}`
    }
  };
}

return {
  json: {
    ...attendee,
    event_id: match.event_id,
    session_id: match.session_id || null,
    match_status: 'matched',
    match_message: `Matched to event: ${match.event_name || match.event_id}`
  }
};

// Prepare the final payload for manual_ticket_entries
const attendee = $('Merge Match Data').item.json;
const customerResult = $input.item.json;

// Get customer_id from upsert result
const customer = Array.isArray(customerResult) ? customerResult[0] : customerResult;
const customerId = customer?.id || null;

// SFF Partner ID
const SFF_PARTNER_ID = '4dec01e6-63a5-4b90-9202-bec0713d1de9';

return {
  json: {
    event_id: attendee.event_id,
    session_id: attendee.session_id,
    partner_id: SFF_PARTNER_ID,
    ticket_count: attendee.ticket_count,
    gross_revenue: 0,
    commission_rate: 0,
    entry_date: attendee.event_date || new Date().toISOString().split('T')[0],
    first_name: attendee.first_name,
    last_name: attendee.last_name,
    email: attendee.email,
    booking_reference: attendee.booking_reference,
    customer_id: customerId,
    source: 'n8n',
    status: 'confirmed',
    notes: `SFF import: ${attendee.event_name}`,
    reference_id: attendee.booking_reference
  }
};

// Handle results - log success/failure counts
const items = $input.all();
let inserted = 0;
let duplicates = 0;
let errors = 0;

for (const item of items) {
  const statusCode = item.json.statusCode || item.json?.headers?.status;
  if (statusCode === 201 || statusCode === 200) {
    inserted++;
  } else if (statusCode === 409) {
    duplicates++;
  } else {
    errors++;
  }
}

return {
  json: {
    summary: `SFF Import Complete`,
    inserted: inserted,
    duplicates_skipped: duplicates,
    errors: errors,
    total_processed: items.length,
    timestamp: new Date().toISOString()
  }
};
